INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('b570775a-e371-55ae-97eb-f6cd905903d7', '82f91108-38f0-4b1a-b73e-fbaacd6dc557', '___ will do my best to complete the assignment by the deadline.', '我會盡我最大的努力在截止日期前完成這項作業。', 'I', 'He', 'She', 'They', 'I 是第一人稱單數主格代名詞。', '看到大寫的 I 就想到自己。'),
('3e7b65fd-5349-5fc2-ad76-3bab22924627', '863f960c-9dea-4632-a9cb-3487b5c50eab', 'The birds ___ in the trees.', '那些鳥在樹上。', 'are', 'run', 'jump', 'sing', 'be 動詞，用於複數主詞表示「在某處」。', '複數主詞 (The birds) → are'),
('f1e0fa6f-c14c-5783-a9fc-9db1284162df', '74449081-948e-4337-b24b-e50b8a25cddf', '___ happened to your homework?', '你的作業發生了什麼事？', 'what', 'who', 'which', 'whose', '這是一個疑問代名詞，用於詢問事物。', '看到問句想問『什麼』，就找 what！'),
('3192ed96-cee0-5c25-967f-113caed735bb', '825a281c-8ba8-4992-9d3c-d724865fa454', 'He was so tired that he fell asleep.', '他太累了，以致於他睡著了。', 'that', 'because', 'although', 'unless', '連接詞，用於 so...that 結構，表示『如此...以至於...』。', '表示事情發展的結果。'),
('fc3950a3-1441-5272-b3ad-df1b0d96604b', '6f473860-59ac-4c93-809a-155f5d561a5f', 'I want to go to the park ___ my brother.', '我想和我的哥哥一起去公園。', 'with', 'from', 'by', 'at', '表示「跟隨、伴隨」', '想像跟著某人一起走 → with');
